local player=game.Players.LocalPlayer local uis=game:GetService("UserInputService") local rs=game:GetService("RunService") local ps=game:GetService("Players") local camera=workspace.CurrentCamera local ts=game:GetService("TeleportService") local hs=game:GetService("HttpService") local flying=false local noclip=false local esp=false local fling=false local godmode=false local aimbot=false local speed=50 local walkSpeed=16 local jumpPower=50 local dashSpeed=150 local bodyGyro,bodyVelocity local espFolder=Instance.new("Folder",player:WaitForChild("PlayerGui")) espFolder.Name="ESP" local gui=Instance.new("ScreenGui") local frame=Instance.new("Frame") local texts={} frame.Size=UDim2.new(0,200,0,210) frame.Position=UDim2.new(0,10,0,10) frame.BackgroundColor3=Color3.new(0,0,0) frame.BackgroundTransparency=0.5 frame.Parent=gui gui.Parent=player.PlayerGui local y=0 for i,v in pairs({"飛行速度:50","移動速度:16","ジャンプ力:50","飛行:OFF","Noclip:OFF","ESP:OFF","Fling:OFF","Godmode:OFF","Aimbot:OFF"})do texts[i]=Instance.new("TextLabel") texts[i].Size=UDim2.new(1,0,0.111,0) texts[i].Position=UDim2.new(0,0,0,y) texts[i].Text=v texts[i].TextColor3=Color3.new(1,1,1) texts[i].BackgroundTransparency=1 texts[i].Parent=frame y=y+0.111 end local function updateTexts() texts[1].Text="飛行速度:"..speed texts[2].Text="移動速度:"..walkSpeed texts[3].Text="ジャンプ力:"..jumpPower texts[4].Text= flying and"飛行:ON"or"飛行:OFF" texts[4].TextColor3= flying and Color3.new(0,1,0)or Color3.new(1,0,0) texts[5].Text= noclip and"Noclip:ON"or"Noclip:OFF" texts[5].TextColor3= noclip and Color3.new(0,1,0)or Color3.new(1,0,0) texts[6].Text= esp and"ESP:ON"or"ESP:OFF" texts[6].TextColor3= esp and Color3.new(0,1,0)or Color3.new(1,0,0) texts[7].Text= fling and"Fling:ON"or"Fling:OFF" texts[7].TextColor3= fling and Color3.new(0,1,0)or Color3.new(1,0,0) texts[8].Text= godmode and"Godmode:ON"or"Godmode:OFF" texts[8].TextColor3= godmode and Color3.new(0,1,0)or Color3.new(1,0,0) texts[9].Text= aimbot and"Aimbot:ON"or"Aimbot:OFF" texts[9].TextColor3= aimbot and Color3.new(0,1,0)or Color3.new(1,0,0) end local function createESP(plr) if plr==player then return end local function addESP(c) if not c then return end local r=c:FindFirstChild("HumanoidRootPart") if not r then return end local b=Instance.new("BoxHandleAdornment") b.Size=Vector3.new(4,5,2) b.Adornee=r b.AlwaysOnTop=true b.ZIndex=10 b.Transparency=0.3 b.Color3= plr.TeamColor==player.TeamColor and Color3.new(0,1,0)or Color3.new(1,0,0) b.Parent=espFolder local bl=Instance.new("BillboardGui") bl.Adornee=r bl.Size=UDim2.new(0,100,0,30) bl.StudsOffset=Vector3.new(0,3,0) bl.AlwaysOnTop=true bl.Parent=espFolder local nl=Instance.new("TextLabel") nl.Size=UDim2.new(1,0,1,0) nl.BackgroundTransparency=1 nl.Text=plr.Name nl.TextColor3=Color3.new(1,1,1) nl.TextStrokeTransparency=0.5 nl.Parent=bl end if plr.Character then addESP(plr.Character)end plr.CharacterAdded:Connect(function(c)task.wait()addESP(c)end)end local function toggleESP() esp=not esp for _,v in pairs(espFolder:GetChildren())do v:Destroy()end if esp then for _,p in pairs(ps:GetPlayers())do createESP(p)end end updateTexts()end local function toggleNoclip() noclip=not noclip updateTexts()end rs.Stepped:Connect(function() if noclip and player.Character then for _,p in pairs(player.Character:GetChildren())do if p:IsA("BasePart")then p.CanCollide=false end end end end) local function toggleFling() fling=not fling updateTexts()end local function toggleGodmode() godmode=not godmode if godmode and player.Character then local h=player.Character:FindFirstChild("Humanoid") if h then h.MaxHealth=math.huge h.Health=math.huge h.BreakJointsOnDeath=false end end updateTexts()end local function toggleAimbot() aimbot=not aimbot updateTexts()end local function getClosestPlayer() local cd=100 local cp,np if not player.Character or not player.Character:FindFirstChild("HumanoidRootPart")then return nil,nil end local mp=player.Character.HumanoidRootPart.Position for _,p in pairs(ps:GetPlayers())do if p~=player and p.Character and p.Character:FindFirstChild("Humanoid")and p.Character.Humanoid.Health>0 then local tp=p.Character:FindFirstChild("Head")or p.Character:FindFirstChild("HumanoidRootPart") if tp then local d=(tp.Position-mp).Magnitude if d<cd then cd=d cp=p np=tp end end end end return cp,np end rs.RenderStepped:Connect(function() if aimbot and player.Character and player.Character:FindFirstChild("HumanoidRootPart")then local tp,pt=getClosestPlayer() if tp and pt then local cf=camera.CFrame local lc=CFrame.lookAt(cf.Position,pt.Position) camera.CFrame=cf:Lerp(lc,0.5) end end end) rs.Heartbeat:Connect(function() if fling and player.Character then local r=player.Character:FindFirstChild("HumanoidRootPart") if r then for _,op in pairs(ps:GetPlayers())do if op~=player and op.Character then local or_=op.Character:FindFirstChild("HumanoidRootPart") if or_ and(or_.Position-r.Position).Magnitude<30 then local d=(or_.Position-r.Position).Unit or_.Velocity=d*200+Vector3.new(0,100,0) or_.RotVelocity=Vector3.new(100,100,100) end end end end end end) local function toggleFly() flying=not flying local c=player.Character if not c then return end local h=c:FindFirstChild("Humanoid") local r=c:FindFirstChild("HumanoidRootPart") if not h or not r then return end if flying then h.PlatformStand=true bodyGyro=Instance.new("BodyGyro") bodyGyro.MaxTorque=Vector3.new(9e9,9e9,9e9) bodyGyro.P=10000 bodyGyro.Parent=r bodyVelocity=Instance.new("BodyVelocity") bodyVelocity.MaxForce=Vector3.new(9e9,9e9,9e9) bodyVelocity.Velocity=Vector3.new(0,0,0) bodyVelocity.Parent=r else if bodyGyro then bodyGyro:Destroy()end if bodyVelocity then bodyVelocity:Destroy()end h.PlatformStand=false end updateTexts()end rs.Heartbeat:Connect(function() if not flying then return end local c=player.Character if not c then return end local r=c:FindFirstChild("HumanoidRootPart") if not r or not bodyGyro or not bodyVelocity then return end bodyGyro.CFrame=CFrame.lookAt(r.Position,r.Position+camera.CFrame.LookVector) local md=Vector3.new() local cs= speed if uis:IsKeyDown(Enum.KeyCode.LeftShift)then cs=dashSpeed end if uis:IsKeyDown(Enum.KeyCode.W)then md=md+camera.CFrame.LookVector end if uis:IsKeyDown(Enum.KeyCode.S)then md=md-camera.CFrame.LookVector end if uis:IsKeyDown(Enum.KeyCode.A)then md=md-camera.CFrame.RightVector end if uis:IsKeyDown(Enum.KeyCode.D)then md=md+camera.CFrame.RightVector end if uis:IsKeyDown(Enum.KeyCode.Space)then md=md+Vector3.new(0,1,0) end if uis:IsKeyDown(Enum.KeyCode.LeftControl)then md=md+Vector3.new(0,-1,0) end if md.Magnitude>0 then bodyVelocity.Velocity=md.Unit*cs else bodyVelocity.Velocity=Vector3.new(0,0,0) end end) local function applyStats() if player.Character then local h=player.Character:FindFirstChild("Humanoid") if h then h.WalkSpeed=walkSpeed if h.UseJumpPower then h.JumpPower=jumpPower else h.JumpHeight=jumpPower/3 end end end end uis.InputBegan:Connect(function(i,g) if g then return end if i.KeyCode==Enum.KeyCode.F then toggleFly()end if i.KeyCode==Enum.KeyCode.X then toggleNoclip()end if i.KeyCode==Enum.KeyCode.E then toggleESP()end if i.KeyCode==Enum.KeyCode.G then toggleFling()end if i.KeyCode==Enum.KeyCode.Q then toggleGodmode()end if i.KeyCode==Enum.KeyCode.R then toggleAimbot()end if flying then if i.KeyCode==Enum.KeyCode.Up then speed=math.min(speed+10,200)updateTexts()elseif i.KeyCode==Enum.KeyCode.Down then speed=math.max(speed-10,10)updateTexts()end end if i.KeyCode==Enum.KeyCode.Right then walkSpeed=math.min(walkSpeed+2,100)updateTexts()applyStats()elseif i.KeyCode==Enum.KeyCode.Left then walkSpeed=math.max(walkSpeed-2,1)updateTexts()applyStats()end if i.KeyCode==Enum.KeyCode.PageUp then jumpPower=math.min(jumpPower+5,200)updateTexts()applyStats()elseif i.KeyCode==Enum.KeyCode.PageDown then jumpPower=math.max(jumpPower-5,10)updateTexts()applyStats()end end) player.CharacterAdded:Connect(function() if flying then flying=false if bodyGyro then bodyGyro:Destroy()end if bodyVelocity then bodyVelocity:Destroy()end end applyStats()updateTexts()end) ps.PlayerAdded:Connect(function(p)if esp then createESP(p)end end) applyStats()updateTexts() local serverHop=function() local s=hs:JSONDecode(game:HttpGetAsync("https://games.roblox.com/v1/games/"..game.PlaceId.."/servers/Public?limit=100")).data for _,v in pairs(s)do if v.playing<v.maxPlayers and v.id~=game.JobId then ts:TeleportToPlaceInstance(game.PlaceId,v.id)break end end end local rejoin=function() if #ps:GetPlayers()<=1 then ts:Teleport(game.PlaceId,player)else ts:TeleportToPlaceInstance(game.PlaceId,game.JobId,player)end end uis.InputBegan:Connect(function(i,g) if g then return end if i.KeyCode==Enum.KeyCode.H then serverHop()end if i.KeyCode==Enum.KeyCode.J then rejoin()end end) local ac=hookmetamethod if ac then local oi=ac(game,"__index",function(s,m) if s==player and m:lower()=="kick"then return error("",2)end return oi(s,m)end) local on=ac(game,"__namecall",function(s,...) if s==player and getnamecallmethod():lower()=="kick"then return end return on(s,...)end) end
